import { useRepositoryStore } from "@/store/repository.store";
import type { GitHubRepository } from "@/types/github";
import { mockRepositoryAnalysis } from "@/constants/mock-data";

export default function RepositoryPage() {
  const { user } = useUser();
  const [githubToken, setGithubToken] = useState<string>("");
  const [selectedRepoId, setSelectedRepoId] = useState<number | undefined>();

  const {
    repositories,
    selectedRepository,
    connectionStatus,
    isLoading,
    setRepositories,
    setLoading,
    setConnectionStatus,
    setError,
    selectRepository,
  } = useRepositoryStore();

  // Handle GitHub connection
  const handleConnect = async (token: string) => {
    try {
      setLoading(true);
      setConnectionStatus("connecting");
      setGithubToken(token);

      // Fetch repositories from GitHub
      const response = await fetch(`/api/github/repos?token=${encodeURIComponent(token)}`);

      if (!response.ok) {
        throw new Error("Failed to fetch repositories");
      }

      const data = await response.json();
      setRepositories(data.repositories);
      setConnectionStatus("connected");
      setError(null);
    } catch (error) {
      console.error("Error connecting to GitHub:", error);
      setConnectionStatus("error");
      setError(error instanceof Error ? error.message : "Failed to connect");
    } finally {
      setLoading(false);
    }
  };

  // Handle repository selection
  const handleSelectRepository = async (repo: GitHubRepository) => {
    if (!user) return;

    try {
      setLoading(true);
      setSelectedRepoId(repo.id);

      // Save repository to database
      const response = await fetch("/api/repositories", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          repo_name: repo.name,
          repo_full_name: repo.full_name,
          repo_url: repo.html_url,
          default_branch: repo.default_branch,
          language: repo.language,
          description: repo.description,
          stars: repo.stargazers_count,
          forks: repo.forks_count,
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to save repository");
      }

      const data = await response.json();
      selectRepository(data.repository);
      setError(null);
    } catch (error) {
      console.error("Error selecting repository:", error);
      setError(error instanceof Error ? error.message : "Failed to select repository");
    } finally {
      setLoading(false);
    }
  };

  // Load user's stored repositories on mount
  useEffect(() => {
    if (user) {
      loadStoredRepositories();
    }
  }, [user]);

  const loadStoredRepositories = async () => {
    try {
      const response = await fetch("/api/repositories");
      if (response.ok) {
        const data = await response.json();
        if (data.repositories.length > 0) {
          selectRepository(data.repositories[0]);
        }
      }
    } catch (error) {
      console.error("Error loading stored repositories:", error);
    }
  };

  // Show loading state while user data loads
  if (!user) {
