    return (
      <div className="max-w-4xl mx-auto space-y-8">
        <div className="text-center space-y-4">
          <h1 className="text-3xl font-bold text-[#e5e2e3]">
            Connect Your Repository
          </h1>
          <p className="text-[#908fa0] max-w-2xl mx-auto">
            Connect your GitHub account to analyze repositories, generate documentation,
            and get AI-powered insights for faster onboarding.
          </p>
        </div>

        <GitHubConnect onConnect={handleConnect} />

        {connectionStatus === "error" && (
          <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-lg">
            <p className="text-sm text-red-400">
              Failed to connect to GitHub. Please check your token and try again.
            </p>
          </div>
        )}
      </div>
    );
  }

  // Show repository picker if connected but no repository selected
  if (!selectedRepository) {
    return (
      <div className="max-w-4xl mx-auto space-y-8">
        <div className="text-center space-y-4">
          <h1 className="text-3xl font-bold text-[#e5e2e3]">
            Select a Repository
          </h1>
          <p className="text-[#908fa0] max-w-2xl mx-auto">
            Choose a repository to analyze. We'll help you understand the codebase,
            generate documentation, and create personalized learning paths.
          </p>
        </div>

        <RepositoryPicker
          repositories={repositories}
          selectedId={selectedRepoId}
          onSelect={handleSelectRepository}
          isLoading={isLoading}
        />
      </div>
    );
  }

  // Show repository analysis (using mock data for now)
  const {
    repository,
    techStack,
    fileStructure,
    aiSummary,
    insights,
    contributions,
    metrics,
    analysisSteps,
  } = mockRepositoryAnalysis;

  return (
    <div className="space-y-8">
      {/* Repository Header */}
      <RepositoryHeader repository={repository} />

      {/* Main Grid Layout - 2 Columns */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Left Column - Repository Context */}
